// ═══ HELPERS ═════════════════════════════════════════════════

const formatLinks = (c: any, path: string, id?: string) => {
  const baseUrl = new URL(c.req.url).origin + "/api/v1";
  const self = id ? `${baseUrl}${path}/${id}` : `${baseUrl}${path}`;
  return {
    self,
    collection: id ? `${baseUrl}${path}` : undefined,
  };
};

const createPaginatedResponse = (
  items: any[],
  total: number,
  page: number,
  limit: number,
  links: any
) => {
  const pages = Math.ceil(total / limit);
  return {
    items,
    pagination: {
      total,
      page,
      limit,
      pages,
      has_next: page < pages,
      has_prev: page > 1,
    },
    _links: links,
  };
};

// ═══ RATE LIMITER ════════════════════════════════════════════

// ── Rate Limiter (In-Memory) ────────────────────────────
// Simple per-IP rate limiter for Cloudflare Pages Functions.
// Uses a Map with TTL-based cleanup. Works for single-instance
// dev and low-traffic production. For high-traffic, upgrade to
// Cloudflare KV or Durable Objects.

interface RateEntry {
  count: number;
  resetAt: number;
}

const rateLimitMap = new Map<string, RateEntry>();

// Clean up stale entries every 60 seconds
const CLEANUP_INTERVAL = 60_000;
let lastCleanup = Date.now();

function cleanup() {
  const now = Date.now();
  if (now - lastCleanup < CLEANUP_INTERVAL) return;
  lastCleanup = now;
  for (const [key, entry] of rateLimitMap) {
    if (entry.resetAt < now) rateLimitMap.delete(key);
  }
}

/**
 * Check if a request should be rate-limited.
 * @param key   Unique identifier (e.g., IP + path)
 * @param limit Max requests allowed in the window
 * @param windowMs  Time window in milliseconds
 * @returns { limited: boolean, remaining: number, resetAt: number }
 */
export function checkRateLimit(
  key: string,
  limit: number = 5,
  windowMs: number = 60_000
): { limited: boolean; remaining: number; resetAt: number } {
  cleanup();

  const now = Date.now();
  const entry = rateLimitMap.get(key);

  if (!entry || entry.resetAt < now) {
    // New window
    rateLimitMap.set(key, { count: 1, resetAt: now + windowMs });
    return { limited: false, remaining: limit - 1, resetAt: now + windowMs };
  }

  entry.count++;
  if (entry.count > limit) {
    return { limited: true, remaining: 0, resetAt: entry.resetAt };
  }

  return { limited: false, remaining: limit - entry.count, resetAt: entry.resetAt };
}


// ═══ EMAIL UTILITY ═══════════════════════════════════════════

// ── Email Utility (Google Apps Script Webhook) ─────────────
// Sends emails via a deployed Google Apps Script that uses
// GmailApp.sendEmail() — fully compatible with Cloudflare Workers/Pages.
//
// Setup:
// 1. Create a Google Apps Script at https://script.google.com
// 2. Paste the doPost handler (see below)
// 3. Deploy as Web App → "Anyone" can access
// 4. Copy the URL → put in GOOGLE_SCRIPT_URL env var

/**
 * Google Apps Script code to deploy:
 * 
 * function doPost(e) {
 *   var data = JSON.parse(e.postData.contents);
 *   
 *   var secret = PropertiesService.getScriptProperties().getProperty('WEBHOOK_SECRET');
 *   if (secret && data.secret !== secret) {
 *     return ContentService.createTextOutput(JSON.stringify({ error: "Unauthorized" }))
 *       .setMimeType(ContentService.MimeType.JSON);
 *   }
 *
 *   GmailApp.sendEmail(data.to, data.subject, data.text, {
 *     htmlBody: data.html,
 *     name: data.senderName || "PlayPen House"
 *   });
 *   return ContentService.createTextOutput(JSON.stringify({ success: true }))
 *     .setMimeType(ContentService.MimeType.JSON);
 * }
 */

export interface EmailPayload {
  to: string;
  subject: string;
  text: string;
  html?: string;
  senderName?: string;
}

/**
 * Send an email via the Google Apps Script webhook.
 * Returns true on success, false on failure (never throws).
 */
export async function sendEmail(
  scriptUrl: string,
  webhookSecret: string | undefined,
  payload: EmailPayload
): Promise<boolean> {
  if (!scriptUrl) {
    console.warn("[EMAIL] GOOGLE_SCRIPT_URL not set — email skipped:", payload.subject);
    return false;
  }

  try {
    const res = await fetch(scriptUrl, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        secret: webhookSecret,
        to: payload.to,
        subject: payload.subject,
        text: payload.text,
        html: payload.html || payload.text,
        senderName: payload.senderName || "PlayPen House",
      }),
    });

    if (!res.ok) {
      console.error("[EMAIL] Script returned non-OK:", res.status, await res.text());
      return false;
    }

    console.log("[EMAIL] Sent successfully to:", payload.to, "subject:", payload.subject);
    return true;
  } catch (err: any) {
    console.error("[EMAIL] Failed to send:", err.message);
    return false;
  }
}

