// ═══ APP SETUP ═══════════════════════════════════════════════

const app = new Hono<{ Bindings: Bindings; Variables: Variables }>();

// API Tracking (Dev only persistence)
let globalRequestCount = 0;
const apiStartTime = Date.now();


app.use("*", logger());
app.use("*", cors());

// Request Counter Middleware
app.use("*", async (c, next) => {
  globalRequestCount++;
  await next();
});


// DB Middleware
app.use("*", async (c, next) => {
  const url = c.env.TURSO_URL;
  const authToken = c.env.TURSO_AUTH_TOKEN;

  if (!url || url.includes("your-db-url")) {
    if (c.req.path === "/api/health" || c.req.path === "/api/v1/health") {
      return await next();
    }
    return c.json({
      error: "Database Configuration Error",
      message: "TURSO_URL is missing or using placeholder."
    }, 503);
  }

  try {
    const client = createClient({ url, authToken });
    c.set("db", drizzle(client, { schema }));
    await next();
  } catch (error: any) {
    console.error("DB Connection Error:", error);
    return c.json({
      error: "Service Unavailable",
      message: "Could not connect to the database."
    }, 503);
  }
});

// Error Handling
app.onError((err, c) => {
  console.error("API Error:", err);

  if (err.message.startsWith("VAL:")) {
    return c.json({
      error: "ValidationError",
      message: err.message.replace("VAL:", "").trim(),
      timestamp: new Date().toISOString(),
      path: c.req.path
    }, 422);
  }

  if (err.message.includes("not found")) {
    return c.json({
      error: "NotFound",
      message: err.message,
      timestamp: new Date().toISOString(),
      path: c.req.path
    }, 404);
  }

  return c.json({
    error: "InternalServerError",
    message: "An unexpected error occurred.",
    details: process.env.NODE_ENV === 'development' ? err.message : undefined,
    timestamp: new Date().toISOString(),
    path: c.req.path
  }, 500);
});

// ─── HEALTH CHECK ─────────────────────────────────────────
app.get("/api/health", (c) => c.json({ status: "ok", version: "v1" }));

