// ── STATS ──────────────────────────────────────────────────
v1.get("/stats", (c) => {
  const uptimeMs = Date.now() - apiStartTime;
  const uptimeSec = Math.floor(uptimeMs / 1000);
  const rpm = uptimeSec > 0 ? (globalRequestCount / (uptimeSec / 60)).toFixed(2) : "0.00";

  return c.json({
    total_requests: globalRequestCount,
    uptime_seconds: uptimeSec,
    requests_per_minute: rpm,
    average_latency_ms: "Calculated by client",
    current_time: new Date().toISOString()
  });
});

