// ── POST /wallet/topup ───────────────────────────
walletRouter.post("/topup", async (c) => {
  const db = c.get("db");
  const body = await c.req.json().catch(() => null);

  if (!body?.userId || !body?.amount || body.amount <= 0) {
    throw new Error("VAL: userId and a positive amount are required.");
  }

  const id = crypto.randomUUID();
  const userId = body.userId;
  const amount = Number(body.amount);

  // Get current balance
  const rows = await db.query.walletTransactions.findMany({
    where: (t: any, { eq }: any) => eq(t.userId, userId),
    orderBy: (t: any, { desc }: any) => [desc(t.createdAt)],
    limit: 1,
  });

  const currentBalance = rows.length > 0 ? (rows[0].balanceAfter ?? 0) : 0;
  const newBalance = currentBalance + amount;

  await db.insert(schema.walletTransactions).values({
    id,
    userId,
    amount,
    type: "credit",
    reference: body.reference || "Top-up",
    balanceAfter: newBalance,
    createdAt: new Date(),
  });

  return c.json({
    id,
    balanceAfter: newBalance,
    message: "Wallet topped up successfully",
    _links: formatLinks(c, "/wallet", id),
  }, 201);
});

// ── POST /wallet/charge ──────────────────────────
walletRouter.post("/charge", async (c) => {
  const db = c.get("db");
  const body = await c.req.json().catch(() => null);

  if (!body?.userId || !body?.amount || body.amount <= 0) {
    throw new Error("VAL: userId and a positive amount are required.");
  }

  const id = crypto.randomUUID();
  const userId = body.userId;
  const amount = Number(body.amount);

  // Get current balance
  const rows = await db.query.walletTransactions.findMany({
    where: (t: any, { eq }: any) => eq(t.userId, userId),
    orderBy: (t: any, { desc }: any) => [desc(t.createdAt)],
    limit: 1,
  });

  const currentBalance = rows.length > 0 ? (rows[0].balanceAfter ?? 0) : 0;

  if (currentBalance < amount) {
    throw new Error("VAL: Insufficient wallet balance.");
  }

  const newBalance = currentBalance - amount;

  await db.insert(schema.walletTransactions).values({
    id,
    userId,
    amount,
    type: "debit",
    reference: body.reference || "Payment",
    balanceAfter: newBalance,
    createdAt: new Date(),
  });

  return c.json({
    id,
    balanceAfter: newBalance,
    message: "Wallet charged successfully",
    _links: formatLinks(c, "/wallet", id),
  }, 201);
});

// ── NOTIFICATIONS ──────────────────────────────────────────

const notificationsRouter = new Hono<{ Bindings: Bindings; Variables: Variables }>();

// GET /api/v1/notifications
// Retrieves notifications for the user + all broadcasts
notificationsRouter.get("/", async (c) => {
  try {
    const db = c.get("db");
    const userId = c.req.query("userId");

    const rows = await db.query.notifications.findMany({
      where: userId
        ? or(eq(schema.notifications.userId, userId), isNull(schema.notifications.userId))
        : isNull(schema.notifications.userId),
      orderBy: (n: any, { desc }: any) => [desc(n.createdAt)],
    });

    return c.json({ items: rows });
  } catch (error: any) {
    console.error("Fetch notifications error:", error.message);
    return c.json({ items: [] });
  }
});

// GET /api/v1/notifications/check
// Lightweight poll — returns only unread count + latest notification ID.
// Frontend polls this cheap endpoint and only fetches full list when count changes.
notificationsRouter.get("/check", async (c) => {
  try {
    const db = c.get("db");
    const userId = c.req.query("userId");

    const whereFilter = userId
      ? or(eq(schema.notifications.userId, userId), isNull(schema.notifications.userId))
      : isNull(schema.notifications.userId);

    const [unreadResult] = await db
      .select({ value: count() })
      .from(schema.notifications)
      .where(and(whereFilter, eq(schema.notifications.isRead, 0)));

    const latest = await db.query.notifications.findFirst({
      where: whereFilter,
      orderBy: (n: any, { desc }: any) => [desc(n.createdAt)],
      columns: { id: true, createdAt: true },
    });

    return c.json({
      unreadCount: unreadResult?.value ?? 0,
      latestId: latest?.id ?? null,
      latestAt: latest?.createdAt ?? null,
    });
  } catch (error: any) {
    console.error("Check notifications error:", error.message);
    return c.json({ unreadCount: 0, latestId: null, latestAt: null });
  }
});

// POST /api/v1/notifications
// Creates or broadcasts a notification (Admin only or system)
notificationsRouter.post("/", async (c) => {
  try {
    const db = c.get("db");
    const body = await c.req.json().catch(() => null);

    if (!body?.title || !body?.message) {
      throw new Error("VAL: Title and message are required.");
    }

    const id = crypto.randomUUID();
    await db.insert(schema.notifications).values({
      id,
      userId: body.userId || null,
      title: body.title,
      message: body.message,
      type: body.type || "info",
      isRead: 0,
      createdAt: new Date().toISOString(),
    });

    return c.json({ id, message: "Notification sent successfully" }, 201);
  } catch (error: any) {
    console.error("Create notification error:", error.message);
    return c.json({ error: error.message }, 400);
  }
});

// POST /api/v1/notifications/:id/read
notificationsRouter.post("/:id/read", async (c) => {
  try {
    const id = c.req.param("id");
    const db = c.get("db");

    await db.update(schema.notifications)
      .set({ isRead: 1 })
      .where(eq(schema.notifications.id, id));

    return c.json({ message: "Notification marked as read." });
  } catch (error: any) {
    console.error("Mark read error:", error.message);
    return c.json({ error: error.message }, 400);
  }
});

